#!/usr/bin/env python3
# ci/validate_ownership.py
# Asserts that every CODEOWNERS team has an ownership.yaml entry
# and every PagerDuty service is reachable.
# Run as a required CI step on all PRs that touch CODEOWNERS or ownership.yaml.

import re
import sys
import os
import yaml
import requests

CODEOWNERS_PATH = ".github/CODEOWNERS"
OWNERSHIP_PATH = "ops/ownership.yaml"
PD_API_KEY = os.environ["PAGERDUTY_API_KEY"]

def load_codeowners_teams(path: str) -> set[str]:
    teams = set()
    with open(path) as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            parts = line.split()
            for part in parts[1:]:
                if part.startswith("@"):
                    teams.add(part.lstrip("@"))
    return teams

def load_ownership(path: str) -> dict:
    with open(path) as f:
        return yaml.safe_load(f)

def validate_pd_service(service_name: str, api_key: str) -> bool:
    r = requests.get(
        "https://api.pagerduty.com/services",
        params={"query": service_name},
        headers={"Authorization": f"Token token={api_key}", "Accept": "application/vnd.pagerduty+json;version=2"},
        timeout=10,
    )
    r.raise_for_status()
    return any(s["name"] == service_name for s in r.json().get("services", []))

def main() -> int:
    codeowners_teams = load_codeowners_teams(CODEOWNERS_PATH)
    ownership = load_ownership(OWNERSHIP_PATH)
    mapped_teams = set(ownership.get("teams", {}).keys())

    errors = []
    # Every CODEOWNERS team must have an ownership entry
    for team in codeowners_teams:
        if team not in mapped_teams:
            errors.append(f"CODEOWNERS team '{team}' has no entry in {OWNERSHIP_PATH}")

    # Every ownership entry must have a reachable PagerDuty service
    for team, config in ownership.get("teams", {}).items():
        service = config.get("pagerduty_service")
        if not service:
            errors.append(f"Team '{team}' has no pagerduty_service in {OWNERSHIP_PATH}")
        elif not validate_pd_service(service, PD_API_KEY):
            errors.append(f"PagerDuty service '{service}' for team '{team}' not found or inactive")

    if errors:
        print("Ownership validation FAILED:")
        for e in errors:
            print(f"  ERROR: {e}")
        return 1
    print(f"Ownership validation passed: {len(codeowners_teams)} teams mapped correctly.")
    return 0

if __name__ == "__main__":
    sys.exit(main())
